import{c as a,S as t,j as h,m as i}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Banner & Menu","description":"","frontmatter":{},"headers":[],"relativePath":"admin/banner-menu.md","filePath":"admin/banner-menu.md","lastUpdated":0}'),r={name:"admin/banner-menu.md"};function e(l,n,o,c,u,s){return t(),h("div",null,[...n[0]||(n[0]=[i('<h1 id="banner-menu" tabindex="-1">Banner &amp; Menu <a class="header-anchor" href="#banner-menu" aria-label="Permalink to “Banner &amp; Menu”">​</a></h1><p><strong>Đường dẫn:</strong></p><ul><li>Banner quảng cáo: <code>https://lamsonedutech.vn/admin/banner/banner</code></li><li>Menu trang chủ: <code>https://lamsonedutech.vn/admin/banner/menu</code></li></ul><h2 id="_1-banner-quang-cao" tabindex="-1">1. Banner quảng cáo <a class="header-anchor" href="#_1-banner-quang-cao" aria-label="Permalink to “1. Banner quảng cáo”">​</a></h2><h3 id="muc-đich" tabindex="-1">Mục đích <a class="header-anchor" href="#muc-đich" aria-label="Permalink to “Mục đích”">​</a></h3><p>Banner là <strong>ảnh / slide</strong> hiển thị trên trang chủ và các trang quan trọng, dùng để:</p><ul><li>Quảng bá khóa học mới.</li><li>Giới thiệu chương trình khuyến mãi.</li><li>Thông báo sự kiện.</li></ul><h3 id="danh-sach-banner" tabindex="-1">Danh sách Banner <a class="header-anchor" href="#danh-sach-banner" aria-label="Permalink to “Danh sách Banner”">​</a></h3><p>Cột chính:</p><ul><li>Tên (nội bộ)</li><li>Ảnh xem trước</li><li>Vị trí hiển thị: Trang chủ Slider / Trang khóa học / Popup / Sidebar</li><li>Link điều hướng khi click</li><li>Thời gian hiển thị (từ ngày - đến ngày)</li><li>Thứ tự</li><li>Trạng thái</li></ul><h3 id="tao-banner-moi" tabindex="-1">Tạo Banner mới <a class="header-anchor" href="#tao-banner-moi" aria-label="Permalink to “Tạo Banner mới”">​</a></h3><ol><li>Bấm <strong>Thêm banner</strong>.</li><li>Tải ảnh (PNG/JPG, kích thước theo vị trí - hệ thống có hướng dẫn từng vị trí).</li><li>Nhập: <ul><li><strong>Tên</strong> (nội bộ, không hiển thị)</li><li><strong>Vị trí hiển thị</strong> (chọn từ dropdown)</li><li><strong>Link điều hướng</strong> khi click (URL nội bộ hoặc bên ngoài)</li><li><strong>Mở trong tab mới?</strong> (yes/no)</li><li><strong>Ngày bắt đầu - Ngày kết thúc</strong></li><li><strong>Thứ tự</strong> (số nhỏ hiển thị trước)</li></ul></li><li>Lưu.</li></ol><h3 id="quy-chuan-anh" tabindex="-1">Quy chuẩn ảnh <a class="header-anchor" href="#quy-chuan-anh" aria-label="Permalink to “Quy chuẩn ảnh”">​</a></h3><table tabindex="0"><thead><tr><th>Vị trí</th><th>Tỉ lệ khuyến nghị</th><th>Kích thước</th></tr></thead><tbody><tr><td>Trang chủ - Slider chính</td><td>16:9 hoặc 21:9</td><td>1920×1080 hoặc 2400×1000</td></tr><tr><td>Trang chủ - Side banner</td><td>Vuông</td><td>800×800</td></tr><tr><td>Popup khuyến mãi</td><td>3:4</td><td>900×1200</td></tr><tr><td>Banner footer khóa học</td><td>4:1</td><td>1600×400</td></tr></tbody></table><h3 id="meo" tabindex="-1">Mẹo <a class="header-anchor" href="#meo" aria-label="Permalink to “Mẹo”">​</a></h3><ul><li>Có <strong>CTA rõ ràng</strong> trên ảnh (nút &quot;Đăng ký&quot;, &quot;Xem ngay&quot;).</li><li>Đừng đặt quá 5 banner trong slider chính - học viên chỉ xem 2-3 cái đầu.</li><li>Test trên cả desktop &amp; mobile.</li></ul><h2 id="_2-menu-trang-chu" tabindex="-1">2. Menu trang chủ <a class="header-anchor" href="#_2-menu-trang-chu" aria-label="Permalink to “2. Menu trang chủ”">​</a></h2><h3 id="muc-đich-1" tabindex="-1">Mục đích <a class="header-anchor" href="#muc-đich-1" aria-label="Permalink to “Mục đích”">​</a></h3><p>Menu là thanh điều hướng chính ở <strong>header</strong> và <strong>footer</strong> của website học viên.</p><h3 id="danh-sach-menu" tabindex="-1">Danh sách Menu <a class="header-anchor" href="#danh-sach-menu" aria-label="Permalink to “Danh sách Menu”">​</a></h3><p>Cột chính:</p><ul><li>Tên hiển thị</li><li>Vị trí: Header / Footer / Sidebar</li><li>Link điều hướng</li><li>Có submenu?</li><li>Thứ tự</li><li>Trạng thái</li></ul><h3 id="tao-sua-menu" tabindex="-1">Tạo / Sửa Menu <a class="header-anchor" href="#tao-sua-menu" aria-label="Permalink to “Tạo / Sửa Menu”">​</a></h3><ol><li>Bấm <strong>Thêm menu</strong>.</li><li>Điền: <ul><li><strong>Tên hiển thị</strong> (vd: &quot;Khóa học&quot;, &quot;Bộ đề thi&quot;, &quot;Học liệu&quot;)</li><li><strong>Vị trí</strong>: Header / Footer / Sidebar</li><li><strong>Link</strong>: chọn từ danh sách trang có sẵn hoặc nhập URL</li><li><strong>Icon</strong> (nếu cần)</li><li><strong>Cha</strong> (nếu là submenu, chọn menu cha)</li></ul></li><li><strong>Thứ tự</strong> quyết định vị trí trái-phải / trên-dưới.</li><li>Lưu.</li></ol><h3 id="submenu-menu-nhieu-cap" tabindex="-1">Submenu (menu nhiều cấp) <a class="header-anchor" href="#submenu-menu-nhieu-cap" aria-label="Permalink to “Submenu (menu nhiều cấp)”">​</a></h3><ul><li>Tạo menu cha trước (không gán link).</li><li>Tạo từng menu con, chọn menu cha trong trường <strong>Cha</strong>.</li></ul><h3 id="kiem-tra-truoc-khi-cong-khai" tabindex="-1">Kiểm tra trước khi công khai <a class="header-anchor" href="#kiem-tra-truoc-khi-cong-khai" aria-label="Permalink to “Kiểm tra trước khi công khai”">​</a></h3><ul><li>Sau khi đổi menu, <strong>mở tab ẩn danh</strong> để xem giao diện học viên (không bị cache).</li><li>Đảm bảo các link không bị 404.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Banner mới không hiển thị mặc dù đã bật?</strong> → Kiểm tra ngày bắt đầu - có thể đặt nhầm ngày tương lai. Kiểm tra cache trình duyệt (Ctrl+F5).</p><p><strong>Đặt menu sai thứ tự, sửa hoài không lưu?</strong> → Đảm bảo bấm <strong>Lưu</strong> sau mỗi lần đổi. Nếu menu có submenu, lưu menu cha trước, con sau.</p><p><strong>Muốn tạm tắt cả 1 nhóm banner mùa lễ.</strong> → Dùng bộ lọc theo vị trí, chọn tất cả, bấm <strong>Tắt hàng loạt</strong>.</p>',32)])])}const m=a(r,[["render",e]]);export{d as __pageData,m as default};
